import React, { useState } from "react";
import { useAuth } from "../context/AuthContext";

export default function HeroPage() {
  const { loginUser, registerUser } = useAuth();
  const [isLogin, setIsLogin] = useState(true);
  const [error, setError] = useState("");
  const [form, setForm] = useState({ name: "", email: "", password: "" });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    try {
      if (isLogin) {
        await loginUser(form.email, form.password);
      } else {
        await registerUser(form.name, form.email, form.password);
      }
    } catch (err) {
      setError(err.response?.data?.message || "Authentication failed.");
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-slate-900 to-black text-white flex flex-col justify-center items-center px-4">
      <div className="max-w-4xl w-full grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
        
        {/* Left Side: Hero Brand Text */}
        <div className="text-center md:text-left">
          <span className="bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 text-xs font-semibold px-3 py-1 rounded-full uppercase tracking-wider">
            Task Management Simplified
          </span>
          <h1 className="text-4xl sm:text-5xl font-black tracking-tight mt-4 leading-tight">
            Organize your projects <br />
            <span className="text-indigo-400 bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text text-transparent">
              in real-time.
            </span>
          </h1>
          <p className="text-gray-400 text-sm sm:text-base mt-4 max-w-sm">
            Monitor, update, and manage your pipeline deployments with structural responsive clarity.
          </p>
        </div>

        {/* Right Side: Auth Form Card */}
        <div className="bg-white/5 backdrop-blur-md p-6 sm:p-8 rounded-2xl border border-white/10 shadow-xl w-full">
          <h2 className="text-xl font-bold mb-6 text-center text-white">
            {isLogin ? "Sign In to Dashboard" : "Create Account"}
          </h2>

          {error && <div className="bg-red-500/20 border border-red-500/40 text-red-300 text-xs p-3 rounded-xl mb-4">{error}</div>}

          <form onSubmit={handleSubmit} className="space-y-4 text-gray-900">
            {!isLogin && (
              <input
                type="text"
                placeholder="Full Name"
                required
                className="w-full px-4 py-2.5 rounded-xl border border-transparent bg-white/90 focus:bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
              />
            )}
            <input
              type="email"
              placeholder="Email Address"
              required
              className="w-full px-4 py-2.5 rounded-xl border border-transparent bg-white/90 focus:bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
              value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
            />
            <input
              type="password"
              placeholder="Password"
              required
              className="w-full px-4 py-2.5 rounded-xl border border-transparent bg-white/90 focus:bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
            />
            <button type="submit" className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-2.5 rounded-xl transition-colors text-sm shadow-md mt-2">
              {isLogin ? "Log In" : "Get Started"}
            </button>
          </form>

          <p className="text-center text-xs text-gray-400 mt-6">
            {isLogin ? "Don't have an account?" : "Already have an account?"}{" "}
            <button onClick={() => { setIsLogin(!isLogin); setError(""); }} className="text-indigo-400 hover:underline font-medium ml-1">
              {isLogin ? "Sign Up" : "Sign In"}
            </button>
          </p>
        </div>

      </div>
    </div>
  );
}
